#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char filename[25];
    while (T--) {
        scanf("%s", filename);
        printf("Reading CSV file '%s':\n", filename);
        printf("import csv\n\nwith open('%s', newline='') as csvfile:\n    reader = csv.reader(csvfile)\n    for row in reader:\n        print(row)\n\n", filename);
        printf("Writing CSV file '%s':\n", filename);
        printf("import csv\n\nwith open('%s', 'w', newline='') as csvfile:\n    writer = csv.writer(csvfile)\n    writer.writerow(['Name', 'Age'])\n    writer.writerow(['Alice', 30])\n", filename);
        if (T) printf("\n");
    }
    return 0;
}

