code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String filename = br.readLine().trim();
            out.append("Reading CSV file '").append(filename).append("':\n");
            out.append("import csv\n\n");
            out.append("with open('").append(filename).append("', newline='') as csvfile:\n");
            out.append("    reader = csv.reader(csvfile)\n");
            out.append("    for row in reader:\n");
            out.append("        print(row)\n\n");
            out.append("Writing CSV file '").append(filename).append("':\n");
            out.append("import csv\n\n");
            out.append("with open('").append(filename).append("', 'w', newline='') as csvfile:\n");
            out.append("    writer = csv.writer(csvfile)\n");
            out.append("    writer.writerow(['Name', 'Age'])\n");
            out.append("    writer.writerow(['Alice', 30])\n");
            if (i != T-1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

